function normFen(fen) {
  return fen.split(" ").slice(0, 4).join(" ");
}
function classifyOpening(pgn) {
  const games = parsePgn(pgn);
  const game = games[0];
  if (!game) return void 0;
  const posResult = startingPosition(game.headers);
  if (posResult.isErr) return void 0;
  const pos = posResult.unwrap();
  let deepest;
  for (let node = game.moves.children[0]; node; node = node.children[0]) {
    const move3 = parseSan(pos, node.data.san);
    if (!move3) break;
    makeSanAndPlay(pos, move3);
    const fen = makeFen(pos.toSetup());
    const key = normFen(fen);
    const match = ECO_MAP[key];
    if (match) deepest = match;
  }
  return deepest;
}

